private startFrameThrottle(terminalId: string, pty: IPty): void {
  const active = this.sessions.get(terminalId);
  if (!active) return;

  // Register PTY data listener — accumulates to buffer
  pty.onData((data: string) => {
    active.buffer.push(data);
  });

  // Set up throttle timer
  active.throttleTimer = setInterval(() => {
    if (active.buffer.length > 0) {
      const combined = active.buffer.join('');
      active.buffer = [];

      // Emit OUTPUT event
      this.eventBus.publish(
        TerminalEvents.OUTPUT,
        Channels.TERMINAL,
        { terminalId, data: combined, timestamp: new Date().toISOString() },
        'server',
      );

      // Append to ring buffer, evict oldest if at capacity
      this.ringBuffer.push({
        terminalId,
        data: combined,
        timestamp: new Date().toISOString(),
      });
      if (this.ringBuffer.length > this.RING_BUFFER_CAPACITY) {
        this.ringBuffer.shift();
      }
    }
  }, this.THROTTLE_MS);
}

publish<T = unknown>(
  type: EventType | string,
  channel: string,
  payload: T,
  source: 'server' | 'client' = 'server'
): InternalEvent<T> {
  const event: InternalEvent<T> = {
    id: `evt-${++this.eventCounter}-${Date.now()}`,
    type,
    channel,
    payload,
    timestamp: new Date().toISOString(),
    source,
  };

  // Store in history
  this.history.push(event as InternalEvent);
  if (this.history.length > this.maxHistory) {
    this.history = this.history.slice(-this.maxHistory);
  }

  // Notify type-specific subscribers
  const subs = this.subscribers.get(type);
  if (subs) {
    for (const cb of subs) {
      try {
        cb(payload, event as InternalEvent);
      } catch (err) {
        console.error(`[EventBus] Error in subscriber for ${type}:`, err);
      }
    }
  }

  // Notify wildcard subscribers
  for (const cb of this.wildcardSubscribers) {
    try {
      cb(payload, event as InternalEvent);
    } catch (err) {
      console.error(`[EventBus] Error in wildcard subscriber:`, err);
    }
  }

  return event;
}

private broadcastEvent(event: InternalEvent): void {
  for (const client of this.clients.values()) {
    const message: WSMessage = {
      channel: event.channel,
      type: event.type,
      payload: event.payload,
      timestamp: event.timestamp,
    };

    if (client.subscribedChannels.has(event.channel) || client.subscribedChannels.has('*')) {
      // Apply translation for this client
      if (typeof event.payload === 'object' && event.payload !== null) {
        const { translated } = this.translator.translate(
          event.payload as Record<string, unknown>,
          client.id
        );
        message.payload = translated;
      }
      this.sendToClient(client, message);
    }
  }
}
private sendToClient(client: ClientConnection, message: WSMessage): void {
  if (client.ws.readyState === WebSocket.OPEN) {
    client.ws.send(JSON.stringify(message));
  }
}

function translateString(str: string, mode: DisplayMode): string {
  let result = str;
  for (const entry of TRANSLATIONS) {
    const termsToReplace = [entry.term, ...entry.aliases];
    for (const term of termsToReplace) {
      // Replace whole-word occurrences
      const regex = new RegExp(`\\b${term}\\b`, 'g');
      const replacement = mode === 'simple'
        ? (entry.hiddenInSimpleMode ? 'Processing' : entry.simpleLabel)
        : entry.advancedLabel;
      result = result.replace(regex, replacement);
    }
  }
  return result;
}

