wsClient.on(Channels.WORKFLOW, (message) => {
  if (message.type === 'workflow:step-update') {
    const event = (message.payload as unknown) as DelegateEvent;
    const { executionId, type, stepIndex, stepName, output, timestamp } = event;
    let execution = executionMap.get(executionId);
    if (!execution) {
      execution = {
        id: executionId, workflowId: '', params: {},
        status: 'running' as WorkflowStatus, steps: [],
        startedAt: timestamp, completedAt: null,
      };
    }
    if (execution.status !== 'completed' && execution.status !== 'failed' && execution.status !== 'cancelled') {
      switch (type) {
        case 'queued': case 'started': execution.status = 'running'; break;
        case 'completed': execution.status = 'completed'; execution.completedAt = timestamp; break;
        case 'failed': execution.status = 'failed'; execution.completedAt = timestamp; break;
      }
    }
    if (stepIndex !== undefined && stepName !== undefined) {
      const STEP_STATUS_MAP: Record<string, StepStatus> = {
        queued: 'pending', started: 'running', completed: 'complete', failed: 'failed',
      };
      const step: ExecutionStep = {
        index: stepIndex, name: stepName, status: STEP_STATUS_MAP[type] ?? 'pending',
        output, startedAt: timestamp, completedAt: timestamp,
      };
      const existingIdx = execution.steps.findIndex((s) => s.index === stepIndex);
      if (existingIdx >= 0) { execution.steps[existingIdx] = step; }
      else { execution.steps.push(step); }
    }
    executionMap.set(executionId, execution);
    activeWorkflows.update((workflows) => { /* ... */ });
  }
});

